void solve(int CASE)
{
	const int nn = 1000;
	var dis = vector<int>(nn + 1, INF);
	var Q = queue<pii>();
	int mx = 0;
	Q.push({ 1,dis[1] = 0 });
	while (Q.size()) {
		var[now, d] = Q.front();
		Q.pop();
		if (d > dis[now])continue;
		fa(x, 1, now) {
			int to = now + now / x;
			if (to <= nn and dis[to] > dis[now] + 1) {
				dis[to] = dis[now] + 1;
				mx = max(mx, dis[to]);
				Q.push({ to,dis[to] });
			}
		}
	}

	int n, k; cin >> n >> k;
	var b = vector<int>(n + 1);
	var c = vector<int>(n + 1);
	fa(i, 1, n)cin >> b[i];
	fa(i, 1, n)cin >> c[i];
	k = min(12 * n, k);
	var dp = Vec2<int>(n + 1, k + 1);
	fa(i, 1, n)fa(j, 0, k) {
		dp[i][j] = max(dp[i][j], dp[i - 1][j]);
		if (j + dis[b[i]] <= k)
			dp[i][j + dis[b[i]]] = max(dp[i][j + dis[b[i]]], dp[i - 1][j] + c[i]);
	}
	cout << dp[n][k] << endl;
	return;
}
